            while (current != 1) {
                current = countSetBits(current);
                depth++;
            }
            popcountDepth[i] = depth;
        }

        // Function to count the number of set bits (1s) in a number
        long countSetBits(long n) {
            long count = 0;
            while (n > 0) {
                count += n & 1;
                n >>= 1;
            }
            return count;
        }

        // Create a list of frequency arrays for each possible depth (0 to 5)
        int[][] freq = new int[6][n];

        // Initialize the frequency arrays
        for (int i = 0; i < n; i++) {
            long depth = popcountDepth[i];
            if (depth <= 5) {
                freq[(int) depth][i] = 1;
            }
        }

        // Process the queries
        List<Long> answer = new ArrayList<>();

        for (long[] query : queries) {
            if (query[0] == 1) {
                long l = query[1], r = query[2], k = query[3];
                long count = 0;
                for (int i = (int) l; i <= (int) r; i++) {
                    if (freq[(int) k][i] == 1) {
                        count++;
